      "parameters": {
        "functionCode": "const cities = JSON.parse(items[0].json.cities_json);\nconst niches = JSON.parse(items[0].json.niches_json);\nconst searchStrings = [];\nfor (const niche of niches) {\n  for (const city of cities) {\n    searchStrings.push(`${niche.q} ${city} FL`);\n  }\n}\nreturn [{ json: { searchStringsArray: searchStrings, niches_lookup: niches, cities_lookup: cities } }];"
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000003",
      "name": "Function - Build Search Matrix",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [600, 300]
    },
    {
      "parameters": {
        "method": "POST",
        "url": "=https://api.apify.com/v2/acts/compass~google-maps-scraper/run-sync-get-dataset-items?token={{ $credentials.apifyApiToken }}",
        "sendBody": true,
        "specifyBody": "json",
        "jsonBody": "={\n  \"searchStringsArray\": {{ $json.searchStringsArray }},\n  \"maxCrawledPlacesPerSearch\": 30,\n  \"language\": \"en\",\n  \"countryCode\": \"us\",\n  \"scrapeContacts\": true,\n  \"scrapeReviews\": false,\n  \"scrapeReviewsCount\": 0,\n  \"exportPlaceUrls\": true,\n  \"additionalInfo\": true\n}",
        "options": {
          "timeout": 600000
        }
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000004",
      "name": "HTTP - Apify Google Maps Scraper",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [800, 300],
      "credentials": {
        "httpHeaderAuth": {
          "id": "PLACEHOLDER_APIFY_CRED_ID",
          "name": "Apify API Token"
        }
      }
    },
    {
      "parameters": {
        "functionCode": "// Dedup by place_id, then by domain. Keep first occurrence.\nconst seen = new Set();\nconst out = [];\nfor (const item of items) {\n  const placeId = item.json.placeId || item.json.place_id;\n  const website = item.json.website || '';\n  const domain = website.toLowerCase().replace(/^https?:\\/\\//, '').replace(/^www\\./, '').split('/')[0];\n  const key = placeId || domain || (item.json.title + item.json.address);\n  if (key && !seen.has(key)) {\n    seen.add(key);\n    item.json.domain = domain;\n    out.push(item);\n  }\n}\nreturn out;"
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000005",
      "name": "Function - Dedup",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [1000, 300]
    },
    {
      "parameters": {
        "functionCode": "// Filter: must have website, not FB/IG only, rating >= 3.8, reviews >= 10\nconst out = [];\nfor (const item of items) {\n  const j = item.json;\n  if (!j.website) continue;\n  const dom = (j.domain || '').toLowerCase();\n  if (dom.includes('facebook.com') || dom.includes('instagram.com') || dom.includes('linktr.ee')) continue;\n  const rating = parseFloat(j.totalScore || j.rating || 0);\n  const reviewsCount = parseInt(j.reviewsCount || j.reviews_count || 0, 10);\n  if (rating < 3.8) continue;\n  if (reviewsCount < 10) continue;\n  out.push(item);\n}\nreturn out;"
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000006",
      "name": "Function - Filter Quality",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [1200, 300]
    },
    {
      "parameters": {
        "method": "GET",
        "url": "=https://api.hunter.io/v2/domain-search?domain={{ $json.domain }}&limit=3&type=personal&api_key={{ $credentials.hunterApiKey }}",
        "options": {
          "timeout": 30000,
          "ignoreHttpStatusErrors": true
        }
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000007",
      "name": "HTTP - Hunter Domain Search",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1400, 300]
    },
    {
      "parameters": {
        "functionCode": "// Merge Hunter result into the business record. Pick the most-likely-owner email.\nconst businessFields = $('Function - Filter Quality').item.json;\nconst hunter = items[0].json.data || {};\nconst emails = hunter.emails || [];\n\n// Prioritize: position contains 'owner' or 'principal' > position contains 'manager' > first personal email\nfunction score(e) {\n  const p = (e.position || '').toLowerCase();\n  if (p.includes('owner') || p.includes('principal') || p.includes('president') || p.includes('founder')) return 3;\n  if (p.includes('manager') || p.includes('director')) return 2;\n  if (e.first_name && e.last_name) return 1;\n  return 0;\n}\nemails.sort((a,b) => score(b) - score(a));\nconst pick = emails[0];\nif (!pick || !pick.value) {\n  return [];  // No good email — drop the lead\n}\n\nreturn [{ json: {\n  ...businessFields,\n  contact_email: pick.value,\n  contact_first_name: pick.first_name || '',\n  contact_last_name: pick.last_name || '',\n  contact_position: pick.position || '',\n  hunter_confidence: pick.confidence || 0\n}}];"
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000008",
      "name": "Function - Pick Best Email",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [1600, 300]
    },
    {
      "parameters": {
        "method": "GET",
        "url": "=https://api.millionverifier.com/api/v3/?api={{ $credentials.millionVerifierApiKey }}&email={{ $json.contact_email }}&timeout=20",
        "options": {
          "timeout": 30000
        }
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000009",
      "name": "HTTP - MillionVerifier",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1800, 300]
    },
    {
      "parameters": {
        "conditions": {
          "string": [
            {
              "value1": "={{ $json.result }}",
              "operation": "equal",
              "value2": "ok"
            }
          ]
        }
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000010",
      "name": "IF - Verified Deliverable",
      "type": "n8n-nodes-base.if",
      "typeVersion": 1,
      "position": [2000, 300]
    },
    {
      "parameters": {
        "functionCode": "// Compute GBP optimization score (0-10)\nconst j = $('Function - Pick Best Email').item.json;\nlet score = 0;\nconst photoCount = parseInt(j.imagesCount || 0, 10);\nconst reviewsCount = parseInt(j.reviewsCount || 0, 10);\nconst rating = parseFloat(j.totalScore || 0);\nconst hasWebsite = !!j.website;\nconst categories = (j.categories || j.additionalCategories || []).length + 1;\n\nif (photoCount >= 25) score += 2;\nif (reviewsCount >= 50) score += 2;\nif (rating >= 4.5) score += 2;\nif (hasWebsite) score += 2;\nif (categories >= 3) score += 2;\n\nj.gbp_optimization_score = score;\nj.verification_status = 'ok';\nj.scraped_at = new Date().toISOString();\nreturn [{ json: j }];"
      },
      "id": "1a1a1a1a-0001-0001-0001-000000000011",
      "name": "Function - Compute GBP Score",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [2200, 200]
    },
