        "functionCode": "// Build the businessProfile payload for the first-line generator\nconst j = items[0].json;\nconst businessProfile = {\n  business_name: j.business_name,\n  city: j.city,\n  niche: j.niche || 'general_contractor',\n  gbp_url: j.gbp_url,\n  recent_photos: [],  // n8n could fetch latest from Apify GBP photos endpoint here; left empty by default\n  recent_reviews: [],\n  recent_gbp_posts: [],\n  services_listed: (j.services || '').split('|').filter(Boolean),\n  has_website: !!j.domain,\n  website_quality_notes: j.website_quality_notes || ''\n};\nreturn [{ json: { ...j, businessProfile } }];"
