        "sendHeaders": true,
        "headerParameters": {
          "parameters": [
            { "name": "x-api-key", "value": "={{ $credentials.anthropicApiKey }}" },
            { "name": "anthropic-version", "value": "2023-06-01" },
            { "name": "content-type", "value": "application/json" }
          ]
        },
        "sendBody": true,
        "specifyBody": "json",
        "jsonBody": "={\n  \"model\": \"claude-sonnet-4-6\",\n  \"max_tokens\": 120,\n  \"temperature\": 0.7,\n  \"system\": \"<PASTE THE FIRST-LINE SYSTEM PROMPT FROM personalization/first-line-system-prompt.md HERE AS A SINGLE STRING WITH ESCAPED QUOTES>\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": {{ JSON.stringify($json.businessProfile) }}\n    }\n  ]\n}",
        "options": {
          "timeout": 30000
        }
      },
      "id": "2b2b2b2b-0002-0002-0002-000000000005",
      "name": "HTTP - Claude First-Line",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1000, 300]
    },
