        "jsonBody": "={\n  \"model\": \"claude-sonnet-4-6\",\n  \"max_tokens\": 200,\n  \"temperature\": 0,\n  \"system\": \"<PASTE THE REPLY CLASSIFICATION SYSTEM PROMPT FROM reply-handling/reply-classification-prompt.md>\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": {{ JSON.stringify({original_outbound_email: $json.original_outbound_email, reply_subject: $json.reply_subject, reply_body: $json.reply_body, sender_email: $json.sender_email, sender_first_name: $json.sender_first_name, thread_history: $json.thread_history}) }}\n    }\n  ]\n}",
