        "functionCode": "// Cal.com webhook payload normalization\nconst p = items[0].json;\nconst event = p.payload || p;\nreturn [{ json: {\n  trigger_event: p.triggerEvent || 'BOOKING_CREATED',\n  attendee_email: event.attendees && event.attendees[0] && event.attendees[0].email || '',\n  attendee_name: event.attendees && event.attendees[0] && event.attendees[0].name || '',\n  event_start: event.startTime || '',\n  event_end: event.endTime || '',\n  event_title: event.title || '',\n  booking_uid: event.uid || '',\n  cal_link: event.bookerUrl || event.metadata && event.metadata.videoCallUrl || ''\n}}];"
