        "jsonBody": "={\n  \"model\": \"claude-sonnet-4-6\",\n  \"max_tokens\": 1000,\n  \"temperature\": 0.4,\n  \"system\": \"You generate a discovery-call prep brief for Adam at The Nordic Nerd. The brief is short, practical, and gives Adam the 5 most useful facts to walk into the call with. Format: markdown, max 250 words. Sections: WHO, WHERE THEY ARE (online presence summary), WHY THEY REPLIED (reference first_line_used + their reply), THREE ANGLES TO PROBE (specific talking points based on niche, GBP score, city), POTENTIAL TIER FIT (one-line: lean Starter/Growth/Authority based on data + reason).\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": {{ JSON.stringify({contact: $json, booking_time: $json.booking.event_start}) }}\n    }\n  ]\n}",
