      "parameters": {
        "functionCode": "const tier = $('Function - Parse Manual Trigger').item.json.tier.toLowerCase();\nconst tierMap = {\n  starter: { name: 'Starter', mrr: 1500, template_id: 'PLACEHOLDER_DOCUMENSO_STARTER_TEMPLATE_ID' },\n  growth: { name: 'Growth', mrr: 2000, template_id: 'PLACEHOLDER_DOCUMENSO_GROWTH_TEMPLATE_ID' },\n  authority: { name: 'Authority', mrr: 2500, template_id: 'PLACEHOLDER_DOCUMENSO_AUTHORITY_TEMPLATE_ID' }\n};\nconst t = tierMap[tier];\nif (!t) throw new Error('Invalid tier: ' + tier);\n\nconst dealResp = items[0].json;\nconst dealProps = dealResp.properties || {};\nconst contactId = dealResp.associations && dealResp.associations.contacts && dealResp.associations.contacts.results && dealResp.associations.contacts.results[0] && dealResp.associations.contacts.results[0].id;\n\nreturn [{ json: {\n  ...$('Function - Parse Manual Trigger').item.json,\n  deal_props: dealProps,\n  contact_id: contactId,\n  tier_name: t.name,\n  mrr: t.mrr,\n  template_id: t.template_id\n}}];"
