        "jsonBody": "={\n  \"title\": \"{{ $json.properties.company }} — Nordic Nerd Retainer ({{ $('Function - Resolve Tier').item.json.tier_name }})\",\n  \"recipients\": [\n    {\n      \"name\": \"{{ $json.properties.firstname }} {{ $json.properties.lastname }}\",\n      \"email\": \"{{ $json.properties.email }}\",\n      \"role\": \"SIGNER\"\n    }\n  ],\n  \"meta\": {\n    \"subject\": \"Your Nordic Nerd retainer — review and sign\",\n    \"message\": \"Adam from The Nordic Nerd here — here's the retainer we discussed. Anything to adjust before signing, let me know. — Adam\"\n  },\n  \"customFields\": {\n    \"client_company\": \"{{ $json.properties.company }}\",\n    \"client_city\": \"{{ $json.properties.city }}\",\n    \"tier_name\": \"{{ $('Function - Resolve Tier').item.json.tier_name }}\",\n    \"mrr\": \"{{ $('Function - Resolve Tier').item.json.mrr }}\",\n    \"start_date\": \"{{ $('Function - Resolve Tier').item.json.start_date }}\",\n    \"contract_months\": \"6\"\n  }\n}",
