{
  "name": "05 - Signed -> Onboarding (Documenso -> Stripe -> MailerLite -> HubSpot)",
  "nodes": [
    {
      "parameters": {
        "httpMethod": "POST",
        "path": "documenso-signed",
        "responseMode": "lastNode",
        "options": {}
      },
      "id": "5e5e5e5e-0005-0005-0005-000000000001",
      "name": "Webhook - Documenso Signed",
      "type": "n8n-nodes-base.webhook",
      "typeVersion": 1,
      "position": [200, 300],
      "webhookId": "documenso-signed"
    },
    {
      "parameters": {
        "conditions": {
          "string": [
            {
              "value1": "={{ $json.event }}",
              "operation": "equal",
              "value2": "document.completed"
            }
          ]
        }
      },
      "id": "5e5e5e5e-0005-0005-0005-000000000002",
      "name": "IF - Document Signed Event",
      "type": "n8n-nodes-base.if",
      "typeVersion": 1,
      "position": [400, 300]
    },
    {
      "parameters": {
        "functionCode": "// Extract custom fields and signer info from the Documenso payload\nconst p = items[0].json.payload || items[0].json;\nconst custom = p.customFields || {};\nconst signer = (p.recipients && p.recipients[0]) || {};\nreturn [{ json: {\n  document_id: p.id,\n  document_url: p.documentLink || '',\n  signed_at: p.completedAt || new Date().toISOString(),\n  client_email: signer.email,\n  client_name: signer.name,\n  client_company: custom.client_company,\n  client_city: custom.client_city,\n  tier_name: custom.tier_name,\n  mrr: parseInt(custom.mrr || 0, 10),\n  start_date: custom.start_date,\n  contract_months: parseInt(custom.contract_months || 6, 10)\n}}];"
      },
      "id": "5e5e5e5e-0005-0005-0005-000000000003",
      "name": "Function - Extract Signing Data",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [600, 300]
    },
    {
      "parameters": {
        "functionCode": "const tierMap = {\n  Starter: $env.STRIPE_PRICE_STARTER,\n  Growth: $env.STRIPE_PRICE_GROWTH,\n  Authority: $env.STRIPE_PRICE_AUTHORITY\n};\nconst priceId = tierMap[items[0].json.tier_name];\nif (!priceId) throw new Error('Unknown tier: ' + items[0].json.tier_name);\nreturn [{ json: { ...items[0].json, stripe_price_id: priceId } }];"
      },
      "id": "5e5e5e5e-0005-0005-0005-000000000004",
      "name": "Function - Resolve Stripe Price",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [800, 300]
    },
    {
      "parameters": {
        "method": "POST",
        "url": "https://api.stripe.com/v1/customers",
        "sendHeaders": true,
        "headerParameters": {
          "parameters": [
            { "name": "Authorization", "value": "=Bearer {{ $credentials.stripeSecretKey }}" },
            { "name": "Content-Type", "value": "application/x-www-form-urlencoded" }
          ]
        },
        "sendBody": true,
        "specifyBody": "form",
        "bodyParameters": {
          "parameters": [
            { "name": "email", "value": "={{ $json.client_email }}" },
            { "name": "name", "value": "={{ $json.client_company }}" },
            { "name": "description", "value": "=Nordic Nerd retainer — {{ $json.tier_name }} — signed {{ $json.signed_at }}" },
            { "name": "metadata[tier]", "value": "={{ $json.tier_name }}" },
            { "name": "metadata[client_company]", "value": "={{ $json.client_company }}" },
            { "name": "metadata[signed_document_id]", "value": "={{ $json.document_id }}" },
            { "name": "metadata[contract_months]", "value": "={{ $json.contract_months }}" }
          ]
        },
        "options": { "timeout": 30000 }
      },
      "id": "5e5e5e5e-0005-0005-0005-000000000005",
      "name": "HTTP - Stripe Create Customer",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1000, 300]
    },
    {
      "parameters": {
        "method": "POST",
        "url": "https://api.stripe.com/v1/subscriptions",
        "sendHeaders": true,
        "headerParameters": {
          "parameters": [
            { "name": "Authorization", "value": "=Bearer {{ $credentials.stripeSecretKey }}" },
            { "name": "Content-Type", "value": "application/x-www-form-urlencoded" }
          ]
        },
        "sendBody": true,
        "specifyBody": "form",
        "bodyParameters": {
          "parameters": [
            { "name": "customer", "value": "={{ $json.id }}" },
            { "name": "items[0][price]", "value": "={{ $('Function - Resolve Stripe Price').item.json.stripe_price_id }}" },
            { "name": "collection_method", "value": "send_invoice" },
            { "name": "days_until_due", "value": "7" },
